import toast from 'react-hot-toast';
import { payrollAPI } from '../../api/services';
import { Badge, SkeletonCard, SkeletonTable, Modal, InlineSpinner } from '../../components/common';
import { useAuth } from '../../context/AuthContext';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

/* ── Payslip viewer ── */
function PayslipModal({ payslip, onClose }) {
  if (!payslip) return null;
  const financialData = payslip?.Entry || payslip || {};
  const runData = payslip?.PayrollRun || payslip || {};
  const lines = financialData?.Lines || [];
  const fmt = (v) => Number(v).toLocaleString('en-US', { style: 'currency', currency: 'EGP' });

  return (
    <Modal open={!!payslip} onClose={onClose} title="Payslip Details" size="modal-lg">
      <div style={{ background: 'var(--bg-base)', border: '1px solid var(--border)', borderRadius: 'var(--radius-lg)', padding: 24, marginBottom: 16 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 20 }}>
          <div>
            <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.1rem', fontWeight: 700 }}>Official Payslip</div>
            <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
                Period: {runData?.PeriodStartDate ? `${new Date(runData.PeriodStartDate).toLocaleDateString()} – ${new Date(runData.PeriodEndDate).toLocaleDateString()}` : '—'}
            </div>
          </div>
          <Badge status={payslip?.Status || 'Finalized'}>{payslip?.Status || 'Finalized'}</Badge>
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
          <div>
            <div style={{ fontSize: '0.72rem', fontWeight: 600, color: 'var(--green)', textTransform: 'uppercase', marginBottom: 8 }}>Earnings</div>
            {lines.filter(l => Number(l.Amount) > 0).map((l, i) => (
              <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '5px 0', borderBottom: '1px solid var(--border-light)' }}>
                <span style={{ fontSize: '0.82rem' }}>{l.Description}</span><span>{fmt(l.Amount)}</span>
              </div>
            ))}
          </div>
          <div>
            <div style={{ fontSize: '0.72rem', fontWeight: 600, color: 'var(--red)', textTransform: 'uppercase', marginBottom: 8 }}>Deductions</div>
            {lines.filter(l => Number(l.Amount) < 0).map((l, i) => (
              <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '5px 0', borderBottom: '1px solid var(--border-light)' }}>
                <span style={{ fontSize: '0.82rem' }}>{l.Description}</span><span style={{ color: 'var(--red)' }}>{fmt(Math.abs(l.Amount))}</span>
              </div>
            ))}
          </div>
        </div>
        <div style={{ marginTop: 16, padding: 16, background: 'var(--gold-glow)', borderRadius: 8, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span style={{ fontWeight: 600 }}>FINAL NET PAY</span>
          <span style={{ fontSize: '1.4rem', fontWeight: 700, color: 'var(--gold)' }}>{fmt(financialData.NetPay || 0)}</span>
        </div>
      </div>
    </Modal>
  );
}

function PayKPI({ icon: Icon, label, value, color, sub }) {
    return (
      <div className="stat-card">
        <div className="stat-card-accent" style={{ background: color }} />
        <div className="stat-card-icon" style={{ background: `${color}22` }}><Icon size={20} style={{ color }} /></div>
        <div className="stat-card-value">{value ?? '—'}</div>
        <div className="stat-card-label">{label}</div>
        {sub && <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: 3 }}>{sub}</div>}
      </div>
    );
}

export default function PayrollPage() {
  const { user } = useAuth();
  const isPayroll = ['Payroll', 'HR', 'Admin'].includes(user?.role);
  const isLegal = ['Admin', 'Legal'].includes(user?.role);

  const [tab, setTab] = useState('dashboard');
  const [dashboard, setDash] = useState(null);
  const [runs, setRuns] = useState([]);
  const [myPayslips, setMySlips] = useState([]);
  const [exceptions, setExcept] = useState([]);
  const [selectedSlip, setSlip] = useState(null);
  const [loadDash, setLoadDash] = useState(true);
  const [loadRuns, setLoadRuns] = useState(true);
  const [createRunModal, setCreateRunModal] = useState(false);
  const [saving, setSaving] = useState(false);
  const [runForm, setRunForm] = useState({ PolicyID: 1, PeriodStartDate: '', PeriodEndDate: '', CutoffDate: '', PaymentDate: '' });

  const load = useCallback(() => {
    const extract = (res) => res?.data || res || null;
    if (isPayroll) {
      payrollAPI.getDashboard().then(res => { setDash(extract(res)); setLoadDash(false); }).catch(() => setLoadDash(false));
      payrollAPI.listRuns({ limit: 10 }).then(res => { setRuns(extract(res)?.runs || extract(res) || []); setLoadRuns(false); }).catch(() => setLoadRuns(false));
      payrollAPI.listExceptions().then(res => { setExcept(extract(res)?.exceptions || extract(res) || []); }).catch(() => {});
    } else { setLoadDash(false); setLoadRuns(false); }
    payrollAPI.getMyPayslips().then(res => setMySlips(extract(res)?.payslips || extract(res) || [])).catch(() => {});
  }, [isPayroll]);

  useEffect(() => { load(); }, [load]);

  const handleRunAction = async (runId, action) => {
    try {
      if (action === 'process') await payrollAPI.processRun(runId, {});
      if (action === 'approve') await payrollAPI.approveRun(runId, {});
      if (action === 'finalize') await payrollAPI.finalizeRun(runId);
      if (action === 'payslips') await payrollAPI.generatePayslips(runId);
      toast.success(`Run ${action}d successfully`);
      load();
    } catch (err) { toast.error("Action failed"); }
  };

  const handleBackup = () => {
    const data = JSON.stringify({ runs, exportDate: new Date() });
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `payroll_backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    toast.success("System Backup (Legal-Admin) Created");
  };

  const TABS = [
    { id: 'dashboard', label: 'Dashboard' },
    { id: 'myslips', label: 'My Payslips' },
    ...(isPayroll ? [
      { id: 'runs', label: 'Payroll Runs' },
      { id: 'exceptions', label: `Exceptions (${exceptions.length})` },
      { id: 'config', label: 'System Config' }
    ] : []),
    ...(isLegal ? [{ id: 'legal', label: 'Legal & Compliance' }] : [])
  ];

  return (
    <>
      <div className="page-header">
        <h1>Payroll Engine</h1>
        <p>Manage salary cycles, legal compliance, and system policies</p>
      </div>

      <div className="tabs">
        {TABS.map(({ id, label }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}>{label}</button>
        ))}
      </div>

      {/* ── DASHBOARD ── */}
      {tab === 'dashboard' && (
        <div className="grid-4">
          <PayKPI icon={DollarSign} color="var(--green)" label="Total Net" value={Number(dashboard?.TotalNetAmount || 0).toLocaleString('en-US', { style: 'currency', currency: 'EGP' })} />
          <PayKPI icon={Users} color="var(--blue)" label="Employees Paid" value={dashboard?.TotalEmployees || 0} />
          <PayKPI icon={RefreshCw} color="var(--gold)" label="Active Cycles" value={dashboard?.ActiveRuns || 0} />
          <PayKPI icon={AlertTriangle} color="var(--red)" label="Open Issues" value={exceptions.length} sub="Requires attention" />
        </div>
      )}

      {/* ── MY PAYSLIPS ── */}
      {tab === 'myslips' && (
        <div className="table-wrap">
          <table>
            <thead><tr><th>Period</th><th>Net Pay</th><th>Status</th><th></th></tr></thead>
            <tbody>
              {myPayslips.map((slip, i) => (
                <tr key={i}>
                  <td>{new Date(slip.PayrollRun?.PeriodStartDate || slip.IssueDate).toLocaleDateString('en-US', { month: 'short', year: 'numeric' })}</td>
                  <td style={{ color: 'var(--gold)', fontWeight: 700 }}>{Number(slip.Entry?.NetPay || 0).toLocaleString('en-US', { style: 'currency', currency: 'EGP' })}</td>
                  <td><Badge status={slip.Status || 'Finalized'}>{slip.Status || 'Finalized'}</Badge></td>
                  <td><button className="btn btn-ghost btn-sm" onClick={() => setSlip(slip)}>View</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* ── SYSTEM CONFIG (Payroll Specialist PR-001 to PR-009) ── */}
      {tab === 'config' && isPayroll && (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: 24 }}>
          <div className="card">
            <div className="card-header"><div className="card-title"><Zap size={18} /> Global Policies (PR-001/004)</div></div>
            <div className="card-body">
              <div className="form-group"><label className="form-label">Minimum Wage Cap (EGP)</label><input type="number" className="form-input" defaultValue="6000" /></div>
              <div className="form-group"><label className="form-label">Standard Working Days</label><input type="number" className="form-input" defaultValue="22" /></div>
              <button className="btn btn-primary btn-sm w-full" onClick={() => toast.success("Config Saved")}>Save Policies</button>
            </div>
          </div>
          <div className="card">
            <div className="card-header"><div className="card-title"><TrendingUp size={18} /> Salary Bands (PR-002)</div></div>
            <div className="table-wrap">
              <table>
                <thead><tr><th>Grade</th><th>Range</th><th>Action</th></tr></thead>
                <tbody>
                    <tr><td>Junior</td><td>15k-25k</td><td><button className="btn btn-ghost btn-sm">Edit</button></td></tr>
                    <tr><td>Senior</td><td>35k-60k</td><td><button className="btn btn-ghost btn-sm">Edit</button></td></tr>
                </tbody>
              </table>
            </div>
          </div>
          <div className="card">
            <div className="card-header"><div className="card-title"><Calculator size={18} /> Rules & Elements (PR-006/009)</div></div>
            <div className="card-body">
               <div className="stat-card" style={{padding: 12, marginBottom: 8, display:'flex', justifyContent:'space-between'}}>
                    <strong>Overtime Rule</strong><span>1.35x Multiplier</span>
               </div>
               <div className="stat-card" style={{padding: 12, display:'flex', justifyContent:'space-between'}}>
                    <strong>Housing Allowance</strong><span>Fixed 2,500 EGP</span>
               </div>
               <button className="btn btn-secondary btn-sm w-full" style={{marginTop:12}}>Add Payroll Element</button>
            </div>
          </div>
        </div>
      )}

      {/* ── LEGAL & COMPLIANCE (Legal Admin User Stories) ── */}
      {tab === 'legal' && isLegal && (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: 24 }}>
          <div className="card">
            <div className="card-header"><div className="card-title"><Globe size={18} /> Tax Brackets (Multi-Country)</div></div>
            <div className="table-wrap">
              <table>
                <thead><tr><th>Bracket</th><th>Rate</th><th>Status</th></tr></thead>
                <tbody>
                    <tr><td>0 - 20,000</td><td>0%</td><td><Badge status="Active">Locked</Badge></td></tr>
                    <tr><td>20,001 - 45,000</td><td>10%</td><td><button className="btn btn-ghost btn-sm">Update</button></td></tr>
                </tbody>
              </table>
            </div>
          </div>
          <div className="card">
            <div className="card-header"><div className="card-title"><Scale size={18} /> Social Compliance Rules</div></div>
            <div className="card-body">
              <div className="form-group"><label className="form-label">Employee Insurance %</label><input className="form-input" defaultValue="7.25" /></div>
              <div className="form-group"><label className="form-label">Employer Insurance %</label><input className="form-input" defaultValue="18.75" /></div>
              <button className="btn btn-primary btn-sm w-full">Apply Legal Update</button>
            </div>
          </div>
          <div className="card">
            <div className="card-header"><div className="card-title"><Database size={18} /> System Maintenance</div></div>
            <div className="card-body">
              <p style={{fontSize: '0.8rem', color:'var(--text-secondary)', marginBottom: 12}}>Export full payroll state for auditing and backup.</p>
              <button className="btn btn-success btn-sm w-full" onClick={handleBackup}><Download size={14}/> Backup System Now</button>
            </div>
          </div>
        </div>
      )}

      {/* ── PAYROLL RUNS ── */}
      {tab === 'runs' && isPayroll && (
        <div className="table-wrap">
          <button className="btn btn-primary btn-sm" style={{ marginBottom: 12 }} onClick={() => setCreateRunModal(true)}>New Run</button>
          <table>
            <thead><tr><th>ID</th><th>Period</th><th>Net Pay</th><th>Actions</th></tr></thead>
            <tbody>
              {runs.map((r, i) => (
                <tr key={i}>
                  <td>#{r.PayrollRunID}</td>
                  <td>{new Date(r.PeriodStartDate).toLocaleDateString()}</td>
                  <td>{Number(r.TotalNetAmount).toLocaleString()} EGP</td>
                  <td>
                    <div style={{display:'flex', gap: 8}}>
                        <button className="btn btn-ghost btn-sm" onClick={() => handleRunAction(r.PayrollRunID, 'process')}>Process</button>
                        {r.Status === 'PendingApproval' && <button className="btn btn-success btn-sm" onClick={() => handleRunAction(r.PayrollRunID, 'approve')}>Approve</button>}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <PayslipModal payslip={selectedSlip} onClose={() => setSlip(null)} />

      <Modal open={createRunModal} onClose={() => setCreateRunModal(false)} title="Create Payroll Run" footer={<><button className="btn btn-secondary" onClick={() => setCreateRunModal(false)}>Cancel</button><button className="btn btn-primary">Create</button></>}>
        <div className="form-group"><label className="form-label">Policy ID</label><input className="form-input" type="number" defaultValue="1" /></div>
        <div className="form-row">
            <div className="form-group"><label className="form-label">Start Date</label><input className="form-input" type="date" /></div>
            <div className="form-group"><label className="form-label">End Date</label><input className="form-input" type="date" /></div>
        </div>
      </Modal>
    </>
  );
}
